def check_lic13(x: List[float], y: List[float], numpoints: int, params: Dict[str, float]) -> bool:
    k_pts = int(params["K_PTS"])
    length1 = params["LENGTH1"]
    length2 = params["LENGTH2"]

    if numpoints < 3:
        return False

    found_greater = False
    found_less = False

    for i in range(numpoints - k_pts - 1):
        j = i + k_pts + 1
        d = distance(x[i], y[i], x[j], y[j])
        if d > length1:
            found_greater = True
        if d < length2:
            found_less = True

    return found_greater and found_less

