def decide(numpoints: int, x: List[float], y: List[float], parameters: Dict[str, float], lcm: List[List[str]], pum_diag: List[bool]) -> Tuple[List[bool], List[List[bool]], List[bool], bool]:
    LIC_CHECKS = [
        check_lic1, check_lic2, check_lic3, check_lic4, check_lic5,
        check_lic6, check_lic7, check_lic8, check_lic9, check_lic10,
        check_lic11, check_lic12, check_lic13, check_lic14, check_lic15
    ]

    cmv = []
    for check_func in LIC_CHECKS:
        result = check_func(x, y, numpoints, parameters)
        cmv.append(result)

    pum = [[False] * 15 for _ in range(15)]

    for i in range(15):
        pum[i][i] = pum_diag[i]

    for i in range(15):
        for j in range(15):
            if i != j:
                connector = lcm[i][j]
                if connector == "NOTUSED":
                    pum[i][j] = True
                elif connector == "ANDD":
                    pum[i][j] = cmv[i] and cmv[j]
                elif connector == "ORR":
                    pum[i][j] = cmv[i] or cmv[j]

    fuv = []
    for i in range(15):
        if not pum[i][i]:
            fuv.append(True)
        else:
            all_true = all(pum[i][j] for j in range(15))
            fuv.append(all_true)

    launch = all(fuv)

    return cmv, pum, fuv, launch
